import{_ as n,o as a,c as p,ak as e}from"./chunks/framework.DwHlt8HN.js";const m=JSON.parse('{"title":"操作系统","description":"","frontmatter":{},"headers":[],"relativePath":"cs/os/index.md","filePath":"cs/os/index.md","lastUpdated":1774320699000}'),l={name:"cs/os/index.md"};function r(t,s,i,o,c,b){return a(),p("div",null,[...s[0]||(s[0]=[e(`<h1 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to “操作系统”">​</a></h1><p>计算机科学的基石，也是理解一切上层技术的前提。</p><p>很多人学操作系统是为了面试，但学进去之后会发现：为什么 Java 的线程创建需要调用 OS 的线程？为什么 Redis 能用单线程支撑几十万的 QPS？为什么 NIO 比传统 I/O 高效？这些问题的答案，都藏在操作系统里。</p><p>操作系统的本质是<strong>资源管理</strong>——管理 CPU、内存、磁盘、网络这些硬件资源，为上层应用提供统一、便捷、安全的接口。理解了这套机制，你就理解了整个计算机系统的运转逻辑。</p><p>这篇文章系列覆盖进程与线程、内存管理（虚拟内存、分页、分段）、文件系统、I/O 模型、进程间通信、同步与锁、操作系统调度，以及 Linux 常用命令与实践，帮你从「会用」到「懂原理」的跨越。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>操作系统的知识体系可以分为四个核心模块，每个模块都深刻影响着上层技术的表现。</p><table tabindex="0"><thead><tr><th>方向</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>进程与线程</strong></td><td>进程 vs 线程、进程状态转换、进程间通信（IPC）、线程同步</td></tr><tr><td><strong>内存管理</strong></td><td>虚拟内存、分页/分段、页面置换算法（LRU/FIFO/Clock）、内存碎片</td></tr><tr><td><strong>I/O 与文件系统</strong></td><td>阻塞/非阻塞/异步 I/O、零拷贝、Direct I/O、文件系统（inode/ext4）</td></tr><tr><td><strong>Linux 实践</strong></td><td>进程查看（top/ps）、内存分析（free/vmstat）、I/O 分析（iostat/iotop）</td></tr></tbody></table><h2 id="学习路径建议" tabindex="-1">学习路径建议 <a class="header-anchor" href="#学习路径建议" aria-label="Permalink to “学习路径建议”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第一阶段：进程与线程（1 周）</span></span>
<span class="line"><span>→ 进程与线程的本质区别：什么是资源分配单位 vs 执行单位</span></span>
<span class="line"><span>→ 进程状态转换：新建、就绪、运行、阻塞、终止</span></span>
<span class="line"><span>→ 进程间通信：管道、消息队列、共享内存、信号量、Socket</span></span>
<span class="line"><span>→ 线程同步：互斥锁、读写锁、条件变量、信号量</span></span>
<span class="line"><span>→ 经典问题：哲学家就餐、生产者消费者、死锁的必要条件与处理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二阶段：内存管理（1 周）</span></span>
<span class="line"><span>→ 虚拟内存：为什么需要虚拟内存？地址翻译过程</span></span>
<span class="line"><span>→ 分页机制：页表结构、多级页表、快表（TLB）</span></span>
<span class="line"><span>→ 页面置换算法：LRU 的实现（双向链表 + HashMap）、LFU、Clock 算法</span></span>
<span class="line"><span>→ 内存碎片：内碎片 vs 外碎片、伙伴系统</span></span>
<span class="line"><span>→ 常见面试题：JVM 为什么要分代回收？操作系统如何管理堆内存？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三阶段：I/O 与文件系统（1 周）</span></span>
<span class="line"><span>→ 五种 I/O 模型：阻塞 I/O、非阻塞 I/O、I/O 多路复用、信号驱动 I/O、异步 I/O</span></span>
<span class="line"><span>→ epoll 的原理：红黑树 vs 就绪链表 vs 回调机制</span></span>
<span class="line"><span>→ 零拷贝：mmap + write、sendfile、DMA 辅助拷贝</span></span>
<span class="line"><span>→ 文件系统：inode 结构、目录项、硬链接与软链接</span></span>
<span class="line"><span>→ 磁盘调度算法：FCFS、SCAN、C-SCAN、LOOK</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四阶段：Linux 性能分析（1 周）</span></span>
<span class="line"><span>→ 进程管理：ps、top、htop、pidstat 的用法</span></span>
<span class="line"><span>→ 内存分析：free、vmstat、pmap、cgroup 内存限制</span></span>
<span class="line"><span>→ I/O 分析：iostat、iotop、strace、lsof</span></span>
<span class="line"><span>→ 网络分析：netstat、ss、tcpdump、wireshark</span></span>
<span class="line"><span>→ 实战：模拟一次 CPU 飙升的排查全过程</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><h2 id="几个绕不开的经典问题" tabindex="-1">几个绕不开的经典问题 <a class="header-anchor" href="#几个绕不开的经典问题" aria-label="Permalink to “几个绕不开的经典问题”">​</a></h2><p><strong>问题一：进程和线程的本质区别是什么？</strong></p><p>这个问题看似简单，但能答出深度的人不多。</p><p>从资源角度：进程是资源分配的基本单位，拥有独立的地址空间（代码段、数据段、堆、栈）；线程是 CPU 调度的基本单位，同一进程的线程共享地址空间。</p><p>从开销角度：创建/切换进程需要切换页表、刷新 TLB、切换内核态栈；线程切换只需切换寄存器和栈，开销远小于进程。</p><p>从通信角度：进程间通信（IPC）需要借助操作系统提供的机制（管道、消息队列、共享内存、Socket）；同一进程的线程天然共享内存，通信更简单，但也更容易出错（需要加锁）。</p><p><strong>问题二：为什么 Redis 用单线程还能那么快？</strong></p><p>这个问题考的是对 I/O 模型的深刻理解。</p><p>Redis 所谓的「单线程」指的是<strong>网络 I/O 和命令执行</strong>是单线程的，而不是整个 Redis 是单线程的（后台有持久化、过期删除等线程）。</p><p>Redis 快的原因在于：</p><ol><li><strong>基于内存</strong>：内存操作本身极快</li><li><strong>单线程避免了锁竞争</strong>：没有锁的开销，也没有线程切换的开销</li><li><strong>I/O 多路复用</strong>：用 epoll 监听大量连接，收到请求后才处理</li><li><strong>高效的数据结构</strong>：Redis 内部使用动态字符串（SDS）、压缩列表、跳表等经过优化的数据结构</li></ol><h2 id="面试的核心逻辑" tabindex="-1">面试的核心逻辑 <a class="header-anchor" href="#面试的核心逻辑" aria-label="Permalink to “面试的核心逻辑”">​</a></h2><p>操作系统面试，核心考察三个层次：</p><p><strong>第一层：概念清晰。</strong> 进程和线程的区别？虚拟内存解决了什么问题？什么是死锁？</p><p><strong>第二层：原理理解。</strong> 页面置换算法 LRU 是怎么实现的？epoll 的底层数据结构是什么？上下文切换做了什么？</p><p><strong>第三层：联系实际。</strong> 线上服务器内存不足怎么排查？Redis 为什么用单线程？JVM 的 GC 和 OS 的内存管理有什么关系？</p><blockquote><p>&quot;操作系统的面试，最怕的是『只背结论，不讲原理』。能说出分页机制为什么能解决内存碎片的问题，比单纯说『分页是把内存分成固定大小的块』高出一个层次。&quot;</p></blockquote>`,27)])])}const h=n(l,[["render",r]]);export{m as __pageData,h as default};
